const rules    = $('Load Alert Rules').all().map(i => i.json)
const clusters = $('Load Hot/Active Clusters (Last 2h)').all().map(i => i.json)

const alerts = []

for (const rule of rules) {
  for (const cluster of clusters) {
    let matched = false
    let reason  = ''

    if (rule.rule_type === 'score_threshold') {
      if ((cluster.overall_score || 0) >= (rule.threshold || 75)) {
        matched = true
        reason  = `Score ${Math.round(cluster.overall_score)} >= threshold ${rule.threshold}`
      }
    }

    if (rule.rule_type === 'keyword_match' && rule.keywords?.length) {
      const clusterKeywords = (cluster.keywords || []).map(k => k.toLowerCase())
      const matchedKw = rule.keywords.filter(k => clusterKeywords.includes(k.toLowerCase()))
      if (matchedKw.length > 0) {
        matched = true
        reason  = `Matched keywords: ${matchedKw.join(', ')}`
      }
    }

    if (rule.rule_type === 'velocity_spike') {
      if ((cluster.velocity || 0) >= (rule.velocity_threshold || 10)) {
        matched = true
        reason  = `Velocity ${cluster.velocity} >= threshold ${rule.velocity_threshold}`
      }
    }

    if (matched) {
      alerts.push({
        org_id:     cluster.org_id,
        cluster_id: cluster.id,
        rule_id:    rule.id,
        title:      `Alert: ${rule.name}`,
        message:    `"${cluster.title}" — ${reason}`,
        severity:   (cluster.overall_score || 0) >= 85 ? 'critical' : 'high'
      })
    }
  }
}

return alerts.map(a => ({ json: a }))
